import "fmt"

func solve(n int64, edges [][]int64, label string) int64 {
    adj := make([][]int64, n)
    for _, edge := range edges {
        u := edge[0]
        v := edge[1]
        adj[u] = append(adj[u], v)
        adj[v] = append(adj[v], u)
    }

    maxLen := 0
    labels := []byte(label)

    var dfs func(int64, int64, []byte)
    dfs = func(current int64, visited int64, path []byte) {
        if isPalindrome(path) {
            if len(path) > maxLen {
                maxLen = len(path)
            }
        }
        for _, neighbor := range adj[current] {
            if (visited & (1 << neighbor)) == 0 {
                newPath := append([]byte(path), labels[neighbor])
                dfs(neighbor, visited | (1 << neighbor), newPath)
            }
        }
    }

    for i := 0; i < int(n); i++ {
        initialPath := []byte{labels[i]}
        dfs(int64(i), 1 << int64(i), initialPath)
    }

    return int64(maxLen)
}

func isPalindrome(s []byte) bool {
    for i := 0; i < len(s)/2; i++ {
        if s[i] != s[len(s)-1-i] {
            return false
        }
    }
    return true
}
